generated_oml:
// Sensing components
instance MotorEncoder : DTDFVocab:SensingComponent [
    base:desc "Position encoder mounted on the motor shaft measuring angular position of the permanent‑magnet synchronous motor."
    DTDFVocab:producedData MotorPositionTransmission
]

instance GearboxEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary position encoder mounted on the motor gearbox output measuring angular position of the system."
    DTDFVocab:producedData GearboxPositionTransmission
]

instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor measuring the motor current I_M on the motor shaft."
    DTDFVocab:producedData MotorCurrentTransmission
]

// Data transmitted via MQTT
instance MotorPositionTransmission : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoder
]

instance GearboxPositionTransmission : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoder
]

instance MotorCurrentTransmission : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

// Data stored in the DT
instance MotorPositionData : DTDFVocab:Data [
    base:desc "Stored time‑stamped motor shaft position data produced by MotorEncoder and transmitted via MQTT."
    DTDFVocab:fromData MotorPositionTransmission
    DTDFVocab:inputTo ProcessingComponent
]

instance GearboxPositionData : DTDFVocab:Data [
    base:desc "Stored time‑stamped motor gearbox output position data produced by GearboxEncoder and transmitted via MQTT."
    DTDFVocab:fromData GearboxPositionTransmission
    DTDFVocab:inputTo ProcessingComponent
]

instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Stored time‑stamped motor current data I_M produced by MotorCurrentSensor and transmitted via MQTT."
    DTDFVocab:fromData MotorCurrentTransmission
    DTDFVocab:inputTo ProcessingComponent
]

instance MotorTorqueData : DTDFVocab:Data [
    base:desc "Derived motor torque τ computed by the Processing component from I_M and MotorPositionData."
    DTDFVocab:inputTo ProcessingComponent
]

instance GearboxTorqueData : DTDFVocab:Data [
    base:desc "Derived gearbox torque τ computed by the Processing component from MotorTorqueData and GearboxPositionData."
    DTDFVocab:inputTo ProcessingComponent
]

instance SystemTorqueData : DTDFVocab:Data [
    base:desc "Total system torque τ for the MABI MAX 100 robot computed by the Processing component."
    DTDFVocab:inputTo ProcessingComponent
]

instance MotorOmegaData : DTDFVocab:Data [
    base:desc "Derived motor angular velocity ω computed from MotorPositionData."
    DTDFVocab:inputTo ProcessingComponent
]

instance GearboxOmegaData : DTDFVocab:Data [
    base:desc "Derived gearbox angular velocity ω computed from GearboxPositionData."
    DTDFVocab:inputTo ProcessingComponent
]

instance SystemOmegaData : DTDFVocab:Data [
    base:desc "System angular velocity ω for the MABI MAX 100 robot calculated by the Processing component."
    DTDFVocab:inputTo ProcessingComponent
]

// Enablers
instance MQTTBroker : DTDFVocab:Enabler [
    base:desc "MQTT broker facilitating live streaming of motor and gearbox sensor data at sub‑200 Hz."
    DTDFVocab:enables DashboardService, FrictionIdentificationService
]

instance SimulinkRuntime : DTDFVocab:Enabler [
    base:desc "MATLAB® Simulink runtime executing simulation models for the motor, gearbox, and system."
    DTDFVocab:enables FrictionIdentificationService
]

instance ProcessingComponent : DTDFVocab:Enabler [
    base:desc "Generic C++/Java processing component consuming sensor data, running simulation models, and producing output data traces."
    DTDFVocab:enables DashboardService, FrictionIdentificationService
]

instance AssetAdministrationShell : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell integrating engineering and simulation models with the DT for traceability."
    DTDFVocab:enables FrictionIdentificationService
]

instance DashboardFramework : DTDFVocab:Enabler [
    base:desc "Visualization framework presenting real‑time sensor data, simulation outputs, and friction residuals."
    DTDFVocab:enables DashboardService
]

// Models
instance EngineModelSysML : DTDFVocab:Model [
    base:desc "SysML component diagram depicting the permanent‑magnet synchronous motor, motor gearbox, and cycloidal gearbox in the MABI MAX 100 robot."
    DTDFVocab:inputTo AssetAdministrationShell
]

instance SimulationMotorSimulink : DTDFVocab:Model [
    base:desc "MATLAB® Simulink executable model of the permanent‑magnet synchronous motor."
    DTDFVocab:inputTo SimulinkRuntime, ProcessingComponent
]

instance SimulationGearboxSimulink : DTDFVocab:Model [
    base:desc "MATLAB® Simulink executable model of the motor gearbox."
    DTDFVocab:inputTo SimulinkRuntime, ProcessingComponent
]

instance SimulationSystemSimulink : DTDFVocab:Model [
    base:desc "MATLAB® Simulink executable model of the complete MABI MAX 100 robot system."
    DTDFVocab:inputTo SimulinkRuntime, ProcessingComponent
]

instance FrictionModelWhiteBox : DTDFVocab:Model [
    base:desc "White‑box friction model using Coulomb‑Viscous, Stribeck, Dahl, and LuGre formulations."
    DTDFVocab:inputTo ProcessingComponent
]

instance FrictionModelBlackBox : DTDFVocab:Model [
    base:desc "Black‑box friction model trained on live sensor data."
    DTDFVocab:inputTo ProcessingComponent
]

// Services
instance DashboardService : DTDFVocab:Service [
    base:desc "Interactive dashboard visualising real‑time sensor data, simulated outputs, and friction residuals."
    DTDFVocab:provides FrictionParameterUpdateInsight, DiagnosticTrendInsight
]

instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Continuous, multi‑physics joint friction identification service employing white‑box and black‑box models."
    DTDFVocab:provides FrictionParameterUpdateInsight, UpdateControlParametersAction
]

// Insights
instance FrictionParameterUpdateInsight : DTDFVocab:Insight [
    base:desc "Insight reporting updated friction parameters derived from the FrictionIdentificationService."
]

instance DiagnosticTrendInsight : DTDFVocab:Insight [
    base:desc "Insight summarising diagnostic trends informing control‑parameter adjustments."
]

// Actions
instance UpdateControlParametersAction : DTDFVocab:Action [
    base:desc "Action applying updated control parameters to the robot controller to improve positioning accuracy."
    DTDFVocab:IsAutomatic true
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Real‑time operation: sensor data is streamed instantaneously via MQTT; simulation models compute outputs at the same sample rate as sensor data; the digital shadow processes data and updates model parameters continuously, enabling sub‑second synchronization with robot operation."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "An orchestration of components: the Asset (first axis), the AAS shell exposing engineering models, source data streams via MQTT, the Processing component that consumes and computes data traces, the simulation models producing expected behavior, and a unified dashboard presenting all data; the DT is the integration of these elements in a single, centralized system"
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Design (ideal simulation models), Manufacturing (not explicitly covered), and Operated (dynamic real‑time data collection and model identification during robot operation) – the DT focuses on the operated stage to continuously identify and adapt friction models"
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Continuous identification and updating of white‑box and black‑box friction models; traceability of data generation through the Processing component; comparison of simulated outputs with measured values to validate model fidelity; dynamic adaptation to wear, load, temperature changes; uncertainty handled via ongoing online parameter estimation"
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Physical-to-virtual data transmitted via MQTT (publish/subscribe network protocol) from the PT to the DT; the DT leverages AAS for asset data representation, linking data traces to engineering models"
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Use of SysML for engineering models, MATLAB Simulink for simulation, MQTT for data transport, and Asset Administration Shell (AAS) adhering to Industrie 4.0 specifications"
]
